HRESULT MRFNESCurve::SetReferenceUDF(const CATBaseUnknown_var & ispRefUDF) 
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnNESCurve(_CredentialForNESCurve, this);

	if ((ispRefUDF != NULL_var) && (!!FeatFacadeOnNESCurve))//Check input
	{
		// Valuate attribute key
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValue;

		AttrKey = CATFmAttributeName(_MRFNESCurveReferenceUDF);
		rc = FeatFacadeOnNESCurve.GetValue(AttrKey, FmAttrValue);
		FeatFacadeOnNESCurve.UnsetValue(AttrKey);

		// Get input Curve feature facade
		CATFmFeatureFacade FeatFacadeOnUDF;
		FeatFacadeOnUDF = ispRefUDF;

		if (!!FeatFacadeOnUDF && SUCCEEDED(rc))
		{
			FmAttrValue.Clear();
			FmAttrValue.SetFeature(FeatFacadeOnUDF);

			// Set the feature attribute
			rc = FeatFacadeOnNESCurve.SetValue(AttrKey, FmAttrValue);
		}
	}
	return rc;
} 

HRESULT MRFNESCurve::GetReferenceUDF(CATBaseUnknown_var & ispRefUDF) 
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnTWI(_CredentialForNESCurve, this);

	if (!!FeatFacadeOnTWI)
	{
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValue;
		AttrKey = CATFmAttributeName(_MRFNESCurveReferenceUDF);
		rc = FeatFacadeOnTWI.GetValue(AttrKey, FmAttrValue);

		if (SUCCEEDED(rc))
		{
			// Get the Curve feature facade
			CATFmFeatureFacade FeatFacadeOnSurface;
			rc = FmAttrValue.GetFeature(FeatFacadeOnSurface);

			if (SUCCEEDED(rc))
				rc = FeatFacadeOnSurface.QueryInterfaceOnFeature(IID_CATBaseUnknown, (void**)& ispRefUDF);
		}
	}

	return rc;
}

HRESULT MRFNESCurve::UpdateFeature()
{
	CATFmFeatureFacade FeatFacadeOnNES(_CredentialForNESCurve, this);
	HRESULT rc = FeatFacadeOnNES.IsUpToDate();
	if (S_FALSE == rc)
	{
		rc = FeatFacadeOnNES.Update();
		if (SUCCEEDED(rc))
		{
			CATBaseUnknown *pNESCurveObject = NULL;
			rc = FeatFacadeOnNES.QueryInterfaceOnFeature(IID_CATBaseUnknown, (void**)&pNESCurveObject);
			if (SUCCEEDED(rc) && NULL != pNESCurveObject)
			{
				CATPrtUpdateCom *pUpdateCommand = new CATPrtUpdateCom(pNESCurveObject, 0, 0);

				pNESCurveObject->Release();
				pNESCurveObject = NULL;
			}
		}
	}

	return rc;
} 






